    :   [0-9]
    ;

Constant
    :   IntegerConstant
    ;

fragment
IntegerConstant
    :   DecimalConstant
    |   OctalConstant
    ;

fragment
DecimalConstant
    :   NonzeroDigit Digit*
    ;

fragment
OctalConstant
    :   '0' OctalDigit*
    ;


fragment
NonzeroDigit
    :   [1-9]
    ;

fragment
OctalDigit
    :   [0-7]
    ;


// 预处理信息处理，可以从预处理信息中获得文件名以及行号
// 预处理信息中的第一个数字即为行号
LineAfterPreprocessing
    :   '#' Whitespace* ~[\r\n]*
        {
            // Extract line number and filename from preprocessor directive
            std::string text = getText();
            std::istringstream iss(text.substr(1));
            int lineNum;
            std::string filename;

            if (iss >> lineNum) {
                currentLine = lineNum;

                // Extract filename (may be quoted)
                std::getline(iss, filename);

                // Remove flags part
                size_t spacePos = filename.find(' ');
                if (spacePos != std::string::npos) {
                    filename = filename.substr(0, spacePos);
                }

                // Remove quotes if present
                if (filename.size() >= 2 && filename.front() == '"' && filename.back() == '"') {
                    filename = filename.substr(1, filename.size() - 2);
                }

                currentFilename = filename;
                currentCol = 1;
                atStartOfLine = true;
                hadLeadingSpace = false;
            }
        }
        -> skip
    ;

Whitespace
    :   [ \t]+
        {
            hadLeadingSpace = true;
            currentCol += getText().size();
        }
        -> skip
    ;

// 换行符号，可以利用这个信息来更新行号
Newline
    :   (   '\r' '\n'?
        |   '\n'
        )
        {
            currentLine++;
            currentCol = 1;
            atStartOfLine = true;
            hadLeadingSpace = false;
        }
        -> skip
    ;

// Override emit method to format tokens
@lexer::postinclude {
    virtual std::unique_ptr<antlr4::Token> emit() override {
        auto token = Lexer::emit();

        if (token->getType() == EOF) {
            // Format EOF token as required
            std::ostringstream oss;
            oss << "eof '' Loc=<" << currentFilename << ":" << currentLine << ":" << (currentCol + 1) << ">";
            token->setText(oss.str());
            return token;
        }

        // Get token name and value
        std::string tokenName = _vocabulary.getSymbolicName(token->getType());
        if (tokenName.empty()) {
            tokenName = std::to_string(token->getType());
        }
        std::string tokenValue = token->getText();

        // Format token with location info
        std::ostringstream oss;
        oss << tokenName << " '" << tokenValue << "'";
        if (atStartOfLine) oss << " [StartOfLine]";
        if (hadLeadingSpace) oss << " [LeadingSpace]";
        oss << " Loc=<" << currentFilename << ":" << currentLine << ":" << currentCol << ">";

        token->setText(oss.str());

        // Update position tracking
        currentCol += tokenValue.size();
        atStartOfLine = false;
        hadLeadingSpace = false;

        return token;
    }
}

